```class Solution {
public:
    int maxScore(string s) {
        int n = s.size();
        int ones = 0, zeros = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == '1') ones++;
        }
        int max_score = 0;
        for (int i = 0; i < n - 1; i++) {
            zeros += s[i] == '0';
            max_score = max(max_score, ones - zeros);
        }
        return max_score;
    }
};```
